DROP TABLE IF EXISTS `sys_i18n`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_i18n` (
  `id` varchar(36) NOT NULL COMMENT '主键UUID',
  `lang_key` varchar(200) NOT NULL COMMENT '翻译键（如user.title）',
  `lang_code` varchar(20) NOT NULL COMMENT '语言代码 zh_CN/en_US',
  `lang_value` varchar(1000) NOT NULL COMMENT '翻译内容',
  `module` varchar(100) DEFAULT '' COMMENT '所属模块 user/role/menu/common',
  `status` tinyint(1) DEFAULT '0' COMMENT '状态（0正常 1停用）',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) DEFAULT '' COMMENT '备注',
  `is_backend` tinyint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `sys_i18n_unique` (`lang_key`,`lang_code`,`is_backend`),
  KEY `idx_module` (`module`) COMMENT '模块索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='国际化翻译表';
