/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vehicle_info` (
  `vehicle_id` bigint NOT NULL AUTO_INCREMENT COMMENT '车辆ID',
  `vin` varchar(17) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'VIN码',
  `vehicle_model` bigint DEFAULT NULL COMMENT '车型代码',
  `factory_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '工厂代码',
  `material_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '整车物料号',
  `create_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `remark` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `deleted` tinyint unsigned DEFAULT '0',
  `upload_status` tinyint NOT NULL DEFAULT '0' COMMENT '上传状态(0=未生成 1=已生成 2=未上传 3=上传中 4=上传成功 5=上传失败）',
  `validation_result` tinyint DEFAULT '0' COMMENT '校验结果(0=未校验 1=校验通过 2=校验失败)',
  `status` tinyint DEFAULT '0' COMMENT '状态(0=正常 1=停用)',
  `country` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '国家',
  `color` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '颜色',
  `secondary_color` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '双色的次色',
  `certificate_version` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '证书版本',
  `wvta_no` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'WVTA证书编号',
  `issue_date` datetime DEFAULT NULL COMMENT '发证日期',
  `json` varchar(4000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'json数据',
  `xml_template_id` bigint DEFAULT NULL COMMENT '绑定的xml模板id',
  `vehicle_template_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'COC模板id',
  `factory_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '工厂名称',
  `validation_report_json` varchar(4000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '校验报告的json',
  `engine_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '发电机号',
  `motor_number` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '电机号',
  PRIMARY KEY (`vehicle_id`),
  UNIQUE KEY `vehicle_info_unique` (`vin`,`deleted`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='车辆信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

