--
-- Table structure for table `xml_file`
--

DROP TABLE IF EXISTS `xml_file`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `xml_file` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` bigint DEFAULT NULL COMMENT '文件大小',
  `file_level` varchar(50) DEFAULT NULL COMMENT '文件分级',
  `version` varchar(50) NOT NULL COMMENT '版本号',
  `is_latest` tinyint(1) DEFAULT '1' COMMENT '是否最新版本',
  `pdf_path` varchar(500) DEFAULT NULL COMMENT 'CoC PDF路径',
  `status` tinyint DEFAULT '0' COMMENT '状态(0正常 1停用)',
  `deleted` tinyint DEFAULT '0' COMMENT '删除标志(0存在 2删除)',
  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `xml_template_id` bigint DEFAULT NULL,
  `vin` varchar(30) DEFAULT NULL COMMENT 'VIN',
  `model_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '车型代码',
  `factory_code` varchar(50) DEFAULT NULL COMMENT '工厂代码',
  `vehicle_material_no` varchar(100) DEFAULT NULL COMMENT '整车物料号',
  `country` varchar(50) DEFAULT NULL COMMENT '出口国家',
  `upload_result` varchar(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '上传状态(0=未生成 1=已生成 2=未上传 3=上传中 4=上传成功 5=上传失败）',
  `upload_date` datetime DEFAULT NULL COMMENT '上传日期',
  `issue_date` datetime DEFAULT NULL COMMENT '发证日期',
  `validate_result` tinyint DEFAULT '0' COMMENT '校验结果（0未校验，1校验通过，2校验失败）',
  `validation_report_json` varchar(4000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '校验结果的json',
  PRIMARY KEY (`id`),
  KEY `idx_file_name` (`file_name`),
  KEY `idx_version` (`version`),
  KEY `idx_vin` (`vin`),
  KEY `idx_model_code` (`model_code`),
  KEY `idx_factory_code` (`factory_code`),
  KEY `idx_vehicle_material_no` (`vehicle_material_no`),
  KEY `idx_country` (`country`),
  KEY `idx_upload_result` (`upload_result`),
  KEY `idx_upload_date` (`upload_date`),
  KEY `idx_issue_date` (`issue_date`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='XML文件管理表';
